/*
  Auto-generated from branches_paste_raw.txt — 251 branches.
  Prerequisites: create the QMS database if needed, then run database/schema.sql so dbo.BRANCHES
  and dbo.BRANCH_OPERATING_HOURS exist. If SSMS shows "Invalid object name dbo.BRANCHES" / red
  squiggles, you are on the wrong database or schema was not applied — fix that first, then
  Query Editor → IntelliSense → Refresh Local Cache (Ctrl+Shift+R).

  Run against QMS. BranchCode = MAX(existing)+row (empty DB starts at 101001).
  Service window for new branches: Mon–Fri 09:30–16:00 local (see INSERT into BRANCH_OPERATING_HOURS at end of script).
  After insert, run insert-service-types-all-branches.sql if you need SERVICES rows.

  Manual fix: Sungai Jarom (236) had no coordinates in the source paste — approximate lat/lng were
  inserted in branches_paste_raw.txt; replace with surveyed values if required.
*/

USE QMS;
GO

/* Must stay in this batch with the statements below: table variable @Branches does not survive GO. */
USE QMS;

DECLARE @Branches TABLE (
    RowOrd        INT IDENTITY(1, 1) PRIMARY KEY,
    [Name]        NVARCHAR(200) NOT NULL,
    [Address]     NVARCHAR(400) NOT NULL,
    [State]       NVARCHAR(80) NOT NULL,
    [Latitude]    FLOAT NOT NULL,
    [Longitude]   FLOAT NOT NULL,
    [OperatingHours] NVARCHAR(200) NULL
);


DECLARE @Base INT =
    (SELECT ISNULL(MAX([BranchCode]), 101000) FROM [dbo].[BRANCHES]);

    [Id],
    [BranchCode],
    [Name],
    [Address],
    [State],
    [Latitude],
    [Longitude],
    [OnlineQuotaPercent],
    [SlotDurationMinutes],
    [GeofenceMeters],
    [ServiceZoneOffsetMinutes],
    [OpeningStatus],
    [OperatingHours],
    [ImageUrl],
    [MaxCapacity],
    [AdaptiveSlotCapacityEnabled],
    [MinSlotTotalCapacity]
)
SELECT
    NEWID() AS [Id],
    @Base + b.[RowOrd] AS [BranchCode],
    b.[Name],
    b.[Address],
    b.[State],
    b.[Latitude],
    b.[Longitude],
    70 AS [OnlineQuotaPercent],
    30 AS [SlotDurationMinutes],
    80 AS [GeofenceMeters],
    480 AS [ServiceZoneOffsetMinutes],
    0 AS [OpeningStatus],
    b.[OperatingHours],
    CAST(NULL AS NVARCHAR(800)) AS [ImageUrl],
    CAST(NULL AS INT) AS [MaxCapacity],
    CAST(1 AS BIT) AS [AdaptiveSlotCapacityEnabled],
    CAST(NULL AS INT) AS [MinSlotTotalCapacity]
FROM @Branches AS b
ORDER BY b.[RowOrd];

SELECT
    NEWID(),
    br.Id,
    d.DayOfWeek,
    d.OpenTime,
    d.CloseTime,
    d.IsClosed
FROM dbo.BRANCHES AS br
CROSS JOIN (
    VALUES
        (N'Monday',    CAST('09:30' AS time), CAST('16:00' AS time), 0),
        (N'Tuesday',   CAST('09:30' AS time), CAST('16:00' AS time), 0),
        (N'Wednesday', CAST('09:30' AS time), CAST('16:00' AS time), 0),
        (N'Thursday',  CAST('09:30' AS time), CAST('16:00' AS time), 0),
        (N'Friday',    CAST('09:30' AS time), CAST('16:00' AS time), 0),
        (N'Saturday',  NULL, NULL, 1),
        (N'Sunday',    NULL, NULL, 1)
) AS d(DayOfWeek, OpenTime, CloseTime, IsClosed)
WHERE br.BranchCode > @Base
  AND NOT EXISTS (SELECT 1 FROM dbo.BRANCH_OPERATING_HOURS AS h WHERE h.BranchId = br.Id);

SELECT [BranchCode], [Name], [Id] FROM [dbo].[BRANCHES] WHERE [BranchCode] > @Base ORDER BY [BranchCode];
GO
